import { defineStore } from 'pinia'
export const useChartsStore = defineStore({
    id:'charts',

    state:() => ({
        pressureData:{},
        supNum:0
    }),

    actions:{
        transPressData(pres){
            this.pressureData = pres;
        },
        transSupNumData(sup){
            this.supNum = sup;
        }
    },
})